#!/usr/bin/env bash
# board-service.sh — 投后服务 / board service SOP walkthrough for 风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金).
# Auto-generated by cli_writer.py. Source: research/03-workflows.md.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="风险投资人 / 早期投资判断(GP + Principal — Deal sourcing / 尽调 / 估值与 term sheet / 投后服务 / 退出 + LP 关系与 fundraising — 涵盖 US 美元基金 + 国内 RMB / 美元基金)"
WORKFLOW="投后服务 / board service"

usage() {
  cat <<EOF
board-service.sh — Walk through "${WORKFLOW}" SOP for ${INDUSTRY}

逐步走完这个工作流的入门 SOP, 然后做失败模式自检, 输出走查报告。

USAGE:
  ./board-service.sh             # interactive
  ./board-service.sh --dry-run
  ./board-service.sh --json
  ./board-service.sh --explain
  ./board-service.sh --help
EOF
}

explain() {
  cat <<'EOT'
这个 SOP 走查脚本帮你完成 "投后服务 / board service" 工作流。

一句话: 钱投出去之后,把一个 portfolio 公司从「cap table 上一行」变成「被主动帮扶、被监控、危机时被救」的资产 —— board service、招人、客户介绍、帮融下一轮、危机处理。

入门 SOP 共 5 步, 失败模式自检 4 项。

相关心智模型:
  • Power-law 是世界观，不是事后观察到的结果 — 错过比投错致命: VC 的整门生意建立在「一支基金 80%+（业内估计，幂律分布的概数）回报来自 1-2 个 outlier、其余多数 deal 回本或归零」之上；因此判断一个 deal 的第一性问题不是「它稳不稳 /
  • 市场 / 赛道决定论 — 但「市场 vs 团队谁第一」是本行未决的派系张力: 这一行有一条强力镜片——「好团队遇上烂市场，市场赢；烂团队遇上好市场，市场赢」，市场天花板能不能容下一个 return-the-fund 的 outlier 是早期判断的硬约束；但与之并存的是另一极—

来源: research/03-workflows.md.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a SOP_STEPS=(
  "**建立沟通节奏**:close 后约定固定的更新节奏(月度 / 季度 update + board meeting),让自己能持续看到公司的真实状态。"
  "**定期 board meeting**:拿董事会席位的话,定期开 board meeting,审议关键决策(预算 / 高管任免 / 下一轮融资 / 重大转向)。"
  "**响应式帮扶**:公司有具体求助(招人、找客户、要引荐)时及时接 —— 用基金的网络补公司缺的能力。"
  "**monitor 健康度 + triage**:持续判断每家 portfolio 公司是 default-alive 还是 default-dead,把要救 / 要加注 / 要放弃的公司分类。"
  "**危机 / 退出协助**:公司遇危机时帮处理(裁员 / 桥接融资 / 转型 / 找买家),到退出阶段帮推 IPO / M&A / secondary。"
)
declare -a FAILURE_MODES=(
  "**投后失明**:close 后没建固定沟通节奏,公司出事最后一个知道 —— 「close 后立刻约定月度 / 季度 update + board meeting,把『能持续看到公司真实状态』当投后第一要务」。"
  "**平均分配投后精力**:对 winner 和 loser 一视同仁地投入时间 —— 「按 default-alive / dead 给 portfolio 分级,精力集中到 winner 和『还能救』的公司,对明确失败的快速降投入」。"
  "**把投后当被动客服**:只在创始人开口时才帮 —— 「主动预判公司下一阶段缺什么(销售 VP / CFO / 客户),不等开口就把能力送过去」。"
  "**危机期不作为或反应过慢**:寒冬里 portfolio 公司烧钱过快没及时干预 —— 「定期 triage runway,把要救的公司提前一个月发现,危机期主动介入降 burn / 桥接 / 转型,而不是等 founder 来报丧」。"
)
declare -a STEP_STATUS=()
declare -a STEP_NOTES=()
declare -a FAIL_CHECK=()

ms_section "${INDUSTRY} · ${WORKFLOW} 走查"
ms_info "逐步走完 ${#SOP_STEPS[@]} 步入门 SOP。每步可标 done / skipped / blocked。"
echo

for i in "${!SOP_STEPS[@]}"; do
  ms_section "Step $((i+1))/${#SOP_STEPS[@]}: ${SOP_STEPS[$i]}"
  ms_prompt "状态? [d=done / s=skipped / b=blocked]"
  read -r status
  STEP_STATUS+=("${status:-d}")
  case "${status:-d}" in
    s) ms_prompt "跳过原因 (一句话):"; read -r note ;;
    b) ms_prompt "blocker (一句话):"; read -r note ;;
    *) note="" ;;
  esac
  STEP_NOTES+=("$note")
done

if [[ ${#FAILURE_MODES[@]} -gt 0 ]]; then
  ms_section "失败模式自检"
  for fm in "${FAILURE_MODES[@]}"; do
    if ms_confirm "你是否避免了 — '$fm' ?"; then
      FAIL_CHECK+=("✓ $fm")
    else
      FAIL_CHECK+=("✗ $fm")
    fi
  done
fi

ms_buffer_append "# ${INDUSTRY} — ${WORKFLOW} 走查报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## SOP 步骤"
ms_buffer_append ""
for i in "${!SOP_STEPS[@]}"; do
  status_icon="?"
  case "${STEP_STATUS[$i]}" in
    d|D) status_icon="✓" ;;
    s|S) status_icon="↷" ;;
    b|B) status_icon="✗" ;;
  esac
  if [[ -n "${STEP_NOTES[$i]}" ]]; then
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]} — ${STEP_NOTES[$i]}"
  else
    ms_buffer_append "$((i+1)). [${status_icon}] ${SOP_STEPS[$i]}"
  fi
done
ms_buffer_append ""
if [[ ${#FAIL_CHECK[@]} -gt 0 ]]; then
  ms_buffer_append "## 失败模式自检"
  ms_buffer_append ""
  for line in "${FAIL_CHECK[@]}"; do
    ms_buffer_append "- $line"
  done
  ms_buffer_append ""
fi

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "workflow" "${WORKFLOW}" \
    "step_count" "${#SOP_STEPS[@]}" \
    "failure_check_count" "${#FAILURE_MODES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "board-service-walkthrough"
fi
